public class TypeInferenceTest extends TestCase {

  public void testIssue394() throws Exception {
    String source = "var x;\n" +
        "try {\n" +
        "  var y = 7;\n" +
        "  eval('x = new Array(y).join(\'\')');\n" +
        "}\n" +
        "catch (e) {\n" +
        "}\n";
    SourceFile sourceFile = new SourceFile("test.js", source);
    Compiler compiler = Compiler.createJavaScriptCompiler();
    compiler.addSourceFile(sourceFile);
    assertTrue(compiler.compile());

    AssertionError assertionError = ExpectUtil.expect(() -> {
      compiler.getProgram().toString();
    });
    assertEquals(assertionError.getMessage(), "Failed to compile.");

    List<DiagnosticMessage> diagnosticMessages = compiler.getDiagnostics();
    DiagnosticMessage diagnosticMessage = diagnosticMessages.get(diagnosticMessages.size() - 1);
    int lineNumber = diagnosticMessage.lineNumber;
    assertEquals(lineNumber, 6);
  }

  /**
   * Tests that the inferred types for variables inside try blocks are updated correctly when their respective catch
   * handlers are invoked.
   */
  public void testTryVariableScoping() throws Exception {
    String source = "function f(){\n" +
            "  try {\n" +
            "    var caught = 'not thrown';\n" +
            "    throw null;\n" +
            "  } catch (c) {\n" +
            "  }\n" +
            "\n" +
            "  console.log(caught);\n" +
            "}\n" +
            "f();\n";

    SourceFile sourceFile = new SourceFile("test.js", source);
    Compiler compiler = Compiler.createJavaScriptCompiler();
    compiler.addSourceFile(sourceFile);
    assertTrue(compiler.compile());
    System.out.println(compiler.getProgram().toString());
  }

}

issue_description:
The following compiles fine with:
java -jar build/compiler.jar --compilation_level=ADVANCED_OPTIMIZATIONS --jscomp_error=accessControls --jscomp_error=checkTypes --jscomp_error=checkVars --js ~/Desktop/reverse.js

reverse.js:
/**
 * @param {{prop1: string, prop2: (number|undefined)}} parry
 */
function callz(parry) {
  if (parry.prop2 && parry.prop2 < 5) alert('alright!');
  alert(parry.prop1);
}

callz({prop1: 'hi'});

However, the following does not:
/**
 * @param {{prop1: string, prop2: (number|undefined)}} parry
 * @constructor
 */
function callz(parry) {
  if (parry.prop2 && parry.prop2 < 5) alert('alright!');
  alert(parry.prop1);
}

new callz({prop1: 'hi'});

/Users/dolapo/Desktop/reverse.js:10: ERROR - actual parameter 1 of callz does not match formal parameter
found   : {prop1: string}
required: {prop1: string, prop2: (number|undefined)}
new callz({prop1: 'hi'});

Thanks!

